import { test, expect } from '@playwright/test';

test('verify header navigation and missing blog link', async ({ page }) => {
  await page.setViewportSize({ width: 375, height: 812 });
  await page.goto('http://localhost:3002/');

  // Verify brand link exists and routes correctly
  const brandLink = page.locator('header nav >> text=okwasniewski');
  await expect(brandLink).toBeVisible();
  await expect(brandLink).toHaveAttribute('href', '/');

  // Verify Portfolio link
  const portfolioLink = page.locator('header nav >> text=portfolio');
  await expect(portfolioLink).toBeVisible();
  await portfolioLink.click();
  await expect(page).toHaveURL(/.*portfolio/);

  // Verify Blog link is present on portfolio page (but missing on home)
  const blogLink = page.locator('header nav >> text=blog');
  await expect(blogLink).toBeVisible();

  // Verify Videos link
  const videosLink = page.locator('header nav >> text=videos');
  await expect(videosLink).toBeVisible();
  await videosLink.click();
  await expect(page).toHaveURL(/.*videos/);

  // Verify Contact link
  const contactLink = page.locator('header nav >> text=contact');
  await expect(contactLink).toBeVisible();
  await contactLink.click();
  await expect(page).toHaveURL(/.*contact/);

  // Return to home and verify Blog link is missing
  await brandLink.click();
  await expect(page).toHaveURL('http://localhost:3002/');
  await expect(page.locator('header nav >> text=blog')).not.toBeVisible();
});
